    16→
    17→package server
    18→
    19→import (
    20→	"fmt"
    21→	"os"
    22→	"strconv"
    23→	"strings"
    24→
    25→	"k8s.io/apimachinery/pkg/runtime"
    26→	"k8s.io/apimachinery/pkg/runtime/schema"
    27→	utilruntime "k8s.io/apimachinery/pkg/util/runtime"
    28→	"k8s.io/apimachinery/pkg/util/sets"
    29→	apimachineryversion "k8s.io/apimachinery/pkg/util/version"
    30→	"k8s.io/apiserver/pkg/registry/rest"
    31→	"k8s.io/klog/v2"
    32→)
    33→
    34→// resourceExpirationEvaluator holds info for deciding if a particular rest.Storage needs to excluded from the API
    35→type resourceExpirationEvaluator struct {
    36→	currentVersion *apimachineryversion.Version
    37→	isAlpha        bool
    38→	// This is usually set for testing for which tests need to be removed.  This prevent insta-failing CI.
    39→	// Set KUBE_APISERVER_STRICT_REMOVED_API_HANDLING_IN_ALPHA to see what will be removed when we tag beta
    40→	strictRemovedHandlingInAlpha bool
    41→	// This is usually set by a cluster-admin looking for a short-term escape hatch after something bad happened.
    42→	// This should be made a flag before merge
    43→	// Set KUBE_APISERVER_SERVE_REMOVED_APIS_FOR_ONE_RELEASE to prevent removing APIs for one more release.
    44→	serveRemovedAPIsOneMoreRelease bool
    45→}
    46→
    47→// ResourceExpirationEvaluator indicates whether or not a resource should be served.
    48→type ResourceExpirationEvaluator interface {
    49→	// RemoveDeletedKinds inspects the storage map and modifies it in place by removing storage for kinds that have been deleted.
    50→	// versionedResourcesStorageMap mirrors the field on APIGroupInfo, it's a map from version to resource to the storage.
    51→	RemoveDeletedKinds(groupName string, versioner runtime.ObjectVersioner, versionedResourcesStorageMap map[string]map[string]rest.Storage)
    52→	// ShouldServeForVersion returns true if a particular version cut off is after the current version
    53→	ShouldServeForVersion(majorRemoved, minorRemoved int) bool
    54→}
    55→
    56→func NewResourceExpirationEvaluator(currentVersion *apimachineryversion.Version) (ResourceExpirationEvaluator, error) {
    57→	if currentVersion == nil {
    58→		return nil, fmt.Errorf("empty NewResourceExpirationEvaluator currentVersion")
    59→	}
    60→	klog.V(1).Infof("NewResourceExpirationEvaluator with currentVersion: %s.", currentVersion)
    61→	ret := &resourceExpirationEvaluator{
    62→		strictRemovedHandlingInAlpha: false,
    63→	}
    64→	// Only keeps the major and minor versions from input version.
    65→	ret.currentVersion = apimachineryversion.MajorMinor(currentVersion.Major(), currentVersion.Minor())
    66→	ret.isAlpha = strings.Contains(currentVersion.PreRelease(), "alpha")
    67→
    68→	if envString, ok := os.LookupEnv("KUBE_APISERVER_STRICT_REMOVED_API_HANDLING_IN_ALPHA"); !ok {
    69→		// do nothing
    70→	} else if envBool, err := strconv.ParseBool(envString); err != nil {
    71→		return nil, err
    72→	} else {
    73→		ret.strictRemovedHandlingInAlpha = envBool
    74→	}
    75→
    76→	if envString, ok := os.LookupEnv("KUBE_APISERVER_SERVE_REMOVED_APIS_FOR_ONE_RELEASE"); !ok {
    77→		// do nothing
    78→	} else if envBool, err := strconv.ParseBool(envString); err != nil {
    79→		return nil, err
    80→	} else {
    81→		ret.serveRemovedAPIsOneMoreRelease = envBool
    82→	}
    83→
    84→	return ret, nil
    85→}
    86→
    87→func (e *resourceExpirationEvaluator) shouldServe(gv schema.GroupVersion, versioner runtime.ObjectVersioner, resourceServingInfo rest.Storage) bool {
    88→	internalPtr := resourceServingInfo.New()
    89→
    90→	target := gv
    91→	// honor storage that overrides group version (used for things like scale subresources)
    92→	if versionProvider, ok := resourceServingInfo.(rest.GroupVersionKindProvider); ok {
    93→		target = versionProvider.GroupVersionKind(target).GroupVersion()
    94→	}
    95→
    96→	versionedPtr, err := versioner.ConvertToVersion(internalPtr, target)
    97→	if err != nil {
    98→		utilruntime.HandleError(err)
    99→		return false
   100→	}
   101→
   102→	introduced, ok := versionedPtr.(introducedInterface)
   103→	if ok {
   104→		majorIntroduced, minorIntroduced := introduced.APILifecycleIntroduced()
   105→		verIntroduced := apimachineryversion.MajorMinor(uint(majorIntroduced), uint(minorIntroduced))
   106→		if e.currentVersion.LessThan(verIntroduced) {
   107→			return false
   108→		}
   109→	}
   110→
   111→	removed, ok := versionedPtr.(removedInterface)
   112→	if !ok {
   113→		return true
   114→	}
   115→	majorRemoved, minorRemoved := removed.APILifecycleRemoved()
   116→	return e.ShouldServeForVersion(majorRemoved, minorRemoved)
   117→}
   118→
   119→func (e *resourceExpirationEvaluator) ShouldServeForVersion(majorRemoved, minorRemoved int) bool {
   120→	removedVer := apimachineryversion.MajorMinor(uint(majorRemoved), uint(minorRemoved))
   121→	if removedVer.GreaterThan(e.currentVersion) {
   122→		return true
   123→	}
